import { useState } from "react";
import { WelcomeScreen } from "./screens/WelcomeScreen";
import { TutorialScreen } from "./screens/TutorialScreen";
import { DemoMatchScreen } from "./screens/DemoMatchScreen";
import { MainMenuScreen } from "./screens/MainMenuScreen";
import { LobbyScreen } from "./screens/LobbyScreen";
import { MatchScreen } from "./screens/MatchScreen";

type Screen = "welcome" | "tutorial" | "demo" | "main_menu" | "lobby" | "match";

export default function App() {
  const [currentScreen, setCurrentScreen] = useState<Screen>("welcome");

  return (
    <div className="w-full h-screen eclipse-shell text-[var(--eclipse-text)] overflow-hidden font-sans antialiased selection:bg-[rgba(212,175,55,0.25)]">
      {currentScreen === "welcome" && (
        <WelcomeScreen
          onStartTutorial={() => setCurrentScreen("tutorial")}
          onSkip={() => setCurrentScreen("main_menu")}
        />
      )}
      {currentScreen === "tutorial" && (
        <TutorialScreen onComplete={() => setCurrentScreen("demo")} />
      )}
      {currentScreen === "demo" && (
        <DemoMatchScreen onComplete={() => setCurrentScreen("main_menu")} />
      )}
      {currentScreen === "main_menu" && (
        <MainMenuScreen onNavigate={(screen) => setCurrentScreen(screen)} />
      )}
      {currentScreen === "lobby" && (
        <LobbyScreen
          onBack={() => setCurrentScreen("main_menu")}
          onStart={() => setCurrentScreen("match")}
        />
      )}
      {currentScreen === "match" && (
        <MatchScreen onExit={() => setCurrentScreen("main_menu")} />
      )}
    </div>
  );
}

