  { title: "Cartas de accion", desc: "Las acciones atacan al siguiente jugador, obligandolo a robar." },
  { title: "Reaccion", desc: "Si te atacan, usa una reaccion antes de que termine el tiempo." },
  { title: "Ritual", desc: "Gasta tus sombras para invocar un ritual poderoso." },
  { title: "Eclipse", desc: "Con una carta restante, grita ECLIPSE o recibes penalizacion." },
];

export function TutorialScreen({ onComplete }: Props) {
  const [step, setStep] = useState(0);
  const [shadow, setShadow] = useState(0);
  const [reactionTimer, setReactionTimer] = useState(3);

  useEffect(() => {
    if (step !== 4) return;

    setReactionTimer(3);
    const interval = setInterval(() => {
      setReactionTimer((prev) => {
        if (prev <= 1) {
          clearInterval(interval);
          setStep(5);
          return 0;
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearInterval(interval);
  }, [step]);

  const handleNext = () => {
    if (step < tutorialSteps.length - 1) {
      setStep((prev) => prev + 1);
      return;
