                  transition={{ duration: 1.6, repeat: Infinity }}
                >
                  <Hand className="h-11 w-11" />
                </motion.div>
              )}
            </div>
          </div>

          <div className="px-4 py-5 text-center">
            <h3 className="text-4xl font-extrabold leading-tight">Tu turno! Arrastra para jugar</h3>
