                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -12 }}
                className="mx-4 flex flex-col items-center rounded-2xl border border-[rgba(175,70,84,0.62)] bg-[rgba(51,15,22,0.92)] p-7"
              >
                <Button
